const rows=$input.all().map(i=>i.json);
const now=Date.now(); const stamp=new Date().toISOString();
const istH=Number(new Intl.DateTimeFormat('en-GB',{timeZone:'Asia/Kolkata',hour:'numeric',hourCycle:'h23'}).format(new Date()));
const isOpen=(istH>=7&&istH<23);
const waId=(p)=>{let d=String(p||'').replace(/\D/g,'');if(d.length===10)d='91'+d;else if(d.length===11&&d[0]==='0')d='91'+d.slice(1);return d?d+'@c.us':'';};
const out=[];
for(const r of rows){
  const chat=waId(r.Phone); if(!chat) continue;
  if(String(r.Status||'').toLowerCase().indexOf('cancel')>=0) continue;
  if(String(r.Source||'').toLowerCase().indexOf('seed')>=0) continue;
  const name=r.Name||'there'; const test=r.Test||'your test'; const token=r.Token; const voc=r.VOC_id;
  const booked=Date.parse(r.BookedAt||0); const hrs=isNaN(booked)?0:(now-booked)/3600000;
  const afterHours=String(r.Source||'').indexOf('after-hours')>=0;
  if(afterHours && String(r.Status||'')==='NEW' && !r.Reminder && isOpen){
    out.push({json:{VOC_id:voc,Reminder:stamp,wa_chat_id:chat,wa_text:"🌅 Good morning "+name+"! Kushal Pathology is now *open* (7 AM–11 PM). Your "+test+" (token #"+token+") is ready to be done — visit us anytime today. 🙏"}});
  } else if(String(r.Status||'')==='NEW' && !r.Followup && hrs>=48){
    out.push({json:{VOC_id:voc,Followup:stamp,wa_chat_id:chat,wa_text:"🧪 Hi "+name+", a gentle reminder — your "+test+" (token #"+token+") booking at Kushal Pathology is still open. We're open 7 AM–11 PM, all days. Visit anytime! 🙏"}});
  }
}
return out;
